export function toShopifySuitFormat(product: SuitProduct) {
  return { node: { id: product.id, title: product.title, description: product.description, handle: product.handle, vendor: "LuxeMia", productType: "Suit", tags: product.tags, priceRange: { minVariantPrice: { amount: product.price, currencyCode: product.currency } }, images: { edges: product.images.map((url, i) => ({ node: { url, altText: `${product.title} - Image ${i + 1}` } })) }, variants: { edges: product.variants.map(v => ({ node: { id: v.id, title: v.title, price: { amount: v.price, currencyCode: product.currency }, availableForSale: true, selectedOptions: Object.entries(v.options).map(([name, value]) => ({ name, value })) } })) }, options: product.options } };
}

export function getSuitProductByHandle(handle: string) {
  const product = suitProducts.find(p => p.handle === handle);
  return product ? toShopifySuitFormat(product) : null;
}

export function getAllSuitProducts() { return suitProducts.map(toShopifySuitFormat); }
